class Solution:
    def splitArray(self, nums: List[int], m: int) -> int:
        def ok(limit):
            parts = cnt = 1
            for x in nums:
                if cnt + x > limit:
                    parts += 1; cnt = x
                else: cnt += x
            return parts <= m
        lo, hi = max(nums), sum(nums)
        while lo < hi:
            mid = (lo + hi) // 2
            if ok(mid): hi = mid
            else: lo = mid + 1
        return lo

