class Solution {
public:
    int splitArray(vector<int>& nums, int m) {
        auto ok=[&](long long lim){
            int parts=1; long long s=0;
            for(int x:nums){ if(s+x>lim){ parts++; s=x; } else s+=x; }
            return parts<=m;
        };
        long long lo=*max_element(nums.begin(),nums.end()), hi=accumulate(nums.begin(),nums.end(),0LL);
        while(lo<hi){ long long mid=(lo+hi)/2; if(ok(mid)) hi=mid; else lo=mid+1; }
        return lo;
    }
};

