int splitArray(int* nums, int n, int m) {
    long long lo=0, hi=0;
    for(int i=0;i<n;i++){ if(nums[i]>lo) lo=nums[i]; hi+=nums[i]; }
    while(lo<hi){
        long long mid=(lo+hi)/2; int parts=1; long long s=0; int ok=1;
        for(int i=0;i<n;i++){
            if(s+nums[i]>mid){ parts++; s=nums[i]; if(parts>m){ok=0;break;} }
            else s+=nums[i];
        }
        if(ok&&parts<=m) hi=mid; else lo=mid+1;
    }
    return lo;
}
